// ── Parse AI Analysis & Compute Confidence ──────────────
// Extracts structured JSON from LLM response,
// computes overall confidence, and flags issues.

const mergedData = $('Merge Enrichment Results').first().json;
const aiResponse = $input.first().json;

// Parse AI response
let aiAnalysis = null;
try {
  const text = aiResponse.content?.[0]?.text || '';
  const jsonMatch = text.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    aiAnalysis = JSON.parse(jsonMatch[0]);
  }
} catch (e) {
  // AI analysis failed — continue without it
}

// ── Compute Confidence Score ────
const companyFields = [
  'legal_name', 'industry', 'employee_count', 'estimated_revenue',
  'funding_stage', 'headquarters_city', 'description'
];
const companyFilled = companyFields.filter(f => mergedData.company[f]).length;
const companyConfidence = companyFilled / companyFields.length;

const contactFields = [
  'full_name', 'normalized_title', 'department', 'linkedin_url',
  'phone_direct', 'location_city'
];
const contactFilled = contactFields.filter(f => mergedData.contact[f]).length;
const contactConfidence = contactFilled / contactFields.length;

const aiConfidence = aiAnalysis?.confidence || 0;

// Weighted average
let overallConfidence = (
  companyConfidence * 0.35 +
  contactConfidence * 0.30 +
  aiConfidence * 0.35
);

// Apply penalties
const flags = [];
const reviewReasons = [];

if (mergedData.lead._meta?.is_free_email) {
  flags.push('free_email');
  overallConfidence *= 0.8;
}
if (!mergedData.lead.company_domain) {
  flags.push('no_company_domain');
}
if (!aiAnalysis) {
  flags.push('ai_analysis_failed');
  overallConfidence *= 0.7;
}
if (overallConfidence < 0.4) {
  flags.push('very_low_confidence');
  reviewReasons.push(`Confidence ${(overallConfidence * 100).toFixed(0)}% below threshold`);
}
if (overallConfidence < 0.7 && overallConfidence >= 0.4) {
  flags.push('low_confidence');
  reviewReasons.push(`Confidence ${(overallConfidence * 100).toFixed(0)}% — review recommended`);
}

const enrichedLead = {
  raw_lead: mergedData.lead,
  company: mergedData.company,
  contact: mergedData.contact,
  ai_analysis: aiAnalysis,
  overall_data_confidence: Math.round(overallConfidence * 1000) / 1000,
  flags: flags,
  needs_human_review: reviewReasons.length > 0,
  review_reasons: reviewReasons,
  enrichment_completed_at: new Date().toISOString(),
};

return [{ json: enrichedLead }];

